function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Keep track of the maximum cost (max edge weight) in each connected component
    const maxCosts = new Array(n).fill(0);

    // Iterate through edges in order of increasing weight
