/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Keep track of the maximum cost (max edge weight) in each connected component
    const maxCosts = new Array(n).fill(0);

    // Iterate through edges in order of increasing weight
    for (const [u, v, w] of edges) {
        // Find the current max cost of the components u and v belong to
        const maxU = maxCosts[uf.find(u)];
        const maxV = maxCosts[uf.find(v)];

        // Merge the components
        if (uf.union(u, v)) {
            // Update the max cost of the new component
            maxCosts[uf.find(u)] = Math.max(maxU, maxV, w);
        }
    }

    // The answer is the maximum cost among all components after merging
    return Math.max(...maxCosts);
}

// Union-Find data structure
class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) {
            return false; // Already in the same set
        }

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
        return true;
    }
}

